SELECT '제주 꿈바당어린이도서관', 'MUSEUM', 'NORTH', '제주특별자치도 제주시 연오로 140', 33.4807350, 126.5002152, 120, TRUE, FALSE, 5, 2, 1, 2, 3, 3, 5, '꿈바당 어린이 도서관은 원래 대통령이 제주도를 방문할 때 묵어가던 지방 공간이었다. 1984년 건립된 이후 전두환과 노태우, 김영삼 전 대통령이 총 11회에 걸쳐 이용했으며 1996년 경호시설에서 해제되면서 한때 제주도지사 관사로 사용되기도 했다. 2014년 도민 품으로 돌아온 건물은 여러 논의 끝에 2017년 꿈바당 어린이 도서관으로 새롭게 탈바꿈했다.', TRUE
WHERE NOT EXISTS (SELECT 1 FROM places WHERE name = '제주 꿈바당어린이도서관' AND address = '제주특별자치도 제주시 연오로 140');

