SELECT '제주도자전거대여 용두암하이킹', 'NATURE', 'NORTH', '제주특별자치도 제주시 북성로 31 1층', 33.5156554, 126.5215523, 90, TRUE, FALSE, 4, 4, 1, 1, 4, 4, 3, '"제주도 자전거 환상 코스 및 1100고지 등 제주 자전거 여행을 위한 모든 솔루션이 용두암 하이킹에서는 가능합니다. 국내, 해외단체 여행자들을 위한 차량 및 가이드 서비스부터, 커플 및 개별여행자, 가족여행객들을 위한 다양한 자전거가 준비되어 있습니다. 세계3대 프리미엄 자전거 브랜드인 GIANT 전문 취급 매장으로, 카본로드, 카본MTB 등 스포츠 레저를 위한 프리미엄 자전거, E-MTB를 비롯한 투어전문 자전거가 보유하고 있으며, 자전거 메카닉 지도자 자격증을 보유한 자전거 메인터넌스 기술로 안전을 최우선으로, 최고의 컨디션의 자전거를 대여하고 있습니다.', TRUE
WHERE NOT EXISTS (SELECT 1 FROM places WHERE name = '제주도자전거대여 용두암하이킹' AND address = '제주특별자치도 제주시 북성로 31 1층');

